#define BLOCK_SIZE 16

__kernel void lud_diagonal(__global float* a, const int size, const int offset) {
    int i = get_global_id(0);
    if (i >= BLOCK_SIZE) return;

    int j, k;
    float val, sum, inv_diag;

    // Update row i in the diagonal block (upper triangle part including diagonal)
    // A[i, j] = A[i, j] - sum(A[i, k] * A[k, j]) for k < i
    for (j = i; j < BLOCK_SIZE; j++) {
        sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += a[(offset + i) * size + (offset + k)] * a[(offset + k) * size + (offset + j)];
        }
        a[(offset + i) * size + (offset + j)] -= sum;
    }

    // Compute inverse of diagonal element
    inv_diag = 1.0f / a[(offset + i) * size + (offset + i)];

    // Update column i in the diagonal block (lower triangle part)
    // A[j, i] = (A[j, i] - sum(A[j, k] * A[k, i])) * inv_diag for j > i
    for (j = i + 1; j < BLOCK_SIZE; j++) {
        sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += a[(offset + j) * size + (offset + k)] * a[(offset + k) * size + (offset + i)];
        }
        a[(offset + j) * size + (offset + i)] = (a[(offset + j) * size + (offset + i)] - sum) * inv_diag;
    }
}

__kernel void lud_perimeter(__global float* a, const int size, const int offset) {
    int idx = get_global_id(0);
    int size_inter = size - offset - BLOCK_SIZE;
    int chunks = size_inter / BLOCK_SIZE;

    if (chunks <= 0 || idx >= 2 * chunks) return;

    int chunk_idx;
    int mode; // 0 for Left (lower), 1 for Top (upper)

    if (idx < chunks) {
        chunk_idx = idx;
        mode = 0;
    } else {
        chunk_idx = idx - chunks;
        mode = 1;
    }

    int i, j, k;
    int i_global, j_global;
    float sum;

    if (mode == 0) {
        // Left side: Update A[i_global + i, offset + j]
        // Corresponds to OMP: i_global = offset + BS*(chunk_idx+1), j_global = offset
        i_global = offset + BLOCK_SIZE * (chunk_idx + 1);
        j_global = offset;

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                sum = 0.0f;
                // Sum over k < j: A[i_global+i, j_global+k] * A[offset+k, offset+j]
                for (k = 0; k < j; k++) {
                    sum += a[(i_global + i) * size + (j_global + k)] * a[(offset + k) * size + (offset + j)];
                }
                int row = i_global + i;
                int col = j_global + j;
                float divisor = a[(offset + j) * size + (offset + j)];
                a[row * size + col] = (a[row * size + col] - sum) / divisor;
            }
        }
    } else {
        // Top side: Update A[offset + i, j_global + j]
        // Corresponds to OMP: i_global = offset, j_global = offset + BS*(chunk_idx+1)
        i_global = offset;
        j_global = offset + BLOCK_SIZE * (chunk_idx + 1);

        for (j = 0; j < BLOCK_SIZE; j++) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                sum = 0.0f;
                // Sum over k < i: A[offset+i, offset+k] * A[offset+k, j_global+j]
                for (k = 0; k < i; k++) {
                    sum += a[(offset + i) * size + (offset + k)] * a[(offset + k) * size + (j_global + j)];
                }
                int row = i_global + i;
                int col = j_global + j;
                a[row * size + col] -= sum;
            }
        }
    }
}

__kernel void lud_internal(__global float* a, const int size, const int offset) {
    int gx = get_global_id(0);
    int gy = get_global_id(1);

    int size_inter = size - offset - BLOCK_SIZE;
    int chunks = size_inter / BLOCK_SIZE;

    if (chunks <= 0 || gx >= chunks || gy >= chunks) return;

    int i_global = offset + BLOCK_SIZE * (1 + gy);
    int j_global = offset + BLOCK_SIZE * (1 + gx);

    int i, j, k;
    float sum;

    // Use local arrays to mimic the OMP temp buffers
    // Size is BLOCK_SIZE*BLOCK_SIZE. For BS=16, this is 256 floats = 1KB.
    // This should be safe on most devices.
    float temp_top[BLOCK_SIZE * BLOCK_SIZE];
    float temp_left[BLOCK_SIZE * BLOCK_SIZE];

    // Load top block: A[offset + i, j_global + j]
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_top[i * BLOCK_SIZE + j] = a[(offset + i) * size + (j_global + j)];
        }
    }

    // Load left block: A[i_global + i, offset + j]
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_left[i * BLOCK_SIZE + j] = a[(i_global + i) * size + (offset + j)];
        }
    }

    // Update internal block: A[i_global + i, j_global + j] -= sum(temp_left[i, k] * temp_top[k, j])
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            sum = 0.0f;
            for (k = 0; k < BLOCK_SIZE; k++) {
                sum += temp_left[i * BLOCK_SIZE + k] * temp_top[k * BLOCK_SIZE + j];
            }
            a[(i_global + i) * size + (j_global + j)] -= sum;
        }
    }
}
